import React, { useState, useEffect, useCallback } from "react";
import api from "../api/axios";
import EventCard from "../components/EventCard";
import EventFilters from "../components/EventFilters";

export default function Home() {
  const [events, setEvents] = useState([]);
  const [featured, setFeatured] = useState([]);
  const [loading, setLoading] = useState(true);
  const [nextPage, setNextPage] = useState(null);
  const [activeFilters, setActiveFilters] = useState({});

  const fetchEvents = useCallback(async (params = {}) => {
    setLoading(true);
    try {
      const { data } = await api.get("/events/", { params });
      setEvents(data.results || data);
      setNextPage(data.next || null);
    } catch {
      setEvents([]);
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchFeatured = useCallback(async () => {
    try {
      const { data } = await api.get("/events/", { params: { is_featured: true } });
      setFeatured((data.results || data).slice(0, 3));
    } catch {
      setFeatured([]);
    }
  }, []);

  useEffect(() => {
    fetchEvents();
    fetchFeatured();
  }, [fetchEvents, fetchFeatured]);

  const handleFilter = (params) => {
    setActiveFilters(params);
    fetchEvents(params);
  };

  const loadMore = async () => {
    if (!nextPage) return;
    const url = new URL(nextPage);
    const page = url.searchParams.get("page");
    const { data } = await api.get("/events/", { params: { ...activeFilters, page } });
    setEvents((prev) => [...prev, ...(data.results || data)]);
    setNextPage(data.next || null);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Hero */}
      <div className="text-center mb-10">
        <h1 className="text-4xl font-bold text-gray-900 mb-3">
          Discover Local Events
        </h1>
        <p className="text-lg text-gray-500 max-w-xl mx-auto">
          Find and share events happening in your community — concerts, markets, meetups, and more.
        </p>
      </div>

      {/* Featured */}
      {featured.length > 0 && (
        <section className="mb-10">
          <h2 className="text-xl font-semibold text-gray-800 mb-4 flex items-center gap-2">
            <span className="text-yellow-500">★</span> Featured Events
          </h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
            {featured.map((event) => (
              <EventCard key={event.id} event={event} />
            ))}
          </div>
        </section>
      )}

      {/* Filters */}
      <div className="mb-6">
        <EventFilters onFilter={handleFilter} />
      </div>

      {/* Events Grid */}
      <section>
        <h2 className="text-xl font-semibold text-gray-800 mb-4">All Events</h2>
        {loading ? (
          <div className="flex justify-center py-16">
            <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-primary-600"></div>
          </div>
        ) : events.length === 0 ? (
          <div className="text-center py-16 text-gray-400">
            <svg className="w-14 h-14 mx-auto mb-3 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            <p className="font-medium">No events found</p>
            <p className="text-sm mt-1">Try adjusting your filters.</p>
          </div>
        ) : (
          <>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-5">
              {events.map((event) => (
                <EventCard key={event.id} event={event} />
              ))}
            </div>
            {nextPage && (
              <div className="text-center mt-8">
                <button onClick={loadMore} className="btn-secondary px-8">
                  Load More
                </button>
              </div>
            )}
          </>
        )}
      </section>
    </div>
  );
}
